import{_ as e,c as t,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"プラットフォーム機能: コアコマンドとスキル管理 | OpenSkills","description":"OpenSkillsプラットフォーム機能を学び、コマンド、インストール、リスト、更新、スキル削除などのコア操作をマスターし、グローバル管理とプロジェクト管理の違いを理解しましょう。","frontmatter":{"title":"プラットフォーム機能: コアコマンドとスキル管理 | OpenSkills","sidebarTitle":"コア操作をマスター","subtitle":"プラットフォーム機能: コアコマンドとスキル管理 | OpenSkills","description":"OpenSkillsプラットフォーム機能を学び、コマンド、インストール、リスト、更新、スキル削除などのコア操作をマスターし、グローバル管理とプロジェクト管理の違いを理解しましょう。","order":2},"headers":[],"relativePath":"ja/numman-ali/openskills/platforms/index.md","filePath":"ja/numman-ali/openskills/platforms/index.md"}'),s={name:"ja/numman-ali/openskills/platforms/index.md"};function i(o,a,d,n,h,c){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="プラットフォーム機能" tabindex="-1">プラットフォーム機能 <a class="header-anchor" href="#プラットフォーム機能" aria-label="Permalink to &quot;プラットフォーム機能&quot;">​</a></h1><p>このセクションでは、OpenSkills CLIのコアコマンドとスキル管理機能を深く解説し、「使える」から「熟達する」へのステップアップをサポートします。</p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">始める前に確認してください</p><p>このセクションを学習する前に、<a href="./../start/">クイックスタート</a>セクションを完了していることを確認してください。特に：</p><ul><li><a href="./../start/installation/">OpenSkillsのインストール</a>：OpenSkills CLIのインストールが完了している</li><li><a href="./../start/first-skill/">最初のスキルをインストールする</a>：基本的なスキルインストールプロセスを理解している</li></ul></div><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><p>このセクションには6つのトピックがあり、OpenSkillsの全コア機能を網羅しています：</p><h3 id="コマンド詳解" tabindex="-1"><a href="./cli-commands/">コマンド詳解</a> <a class="header-anchor" href="#コマンド詳解" aria-label="Permalink to &quot;[コマンド詳解](./cli-commands/)&quot;">​</a></h3><p>全7つのコマンド、パラメータ、フラグを完全に紹介し、コマンドクイックリファレンスを提供します。コマンドの使い方をすばやく確認したいユーザーのための適切なガイドです。</p><h3 id="インストールソース詳解" tabindex="-1"><a href="./install-sources/">インストールソース詳解</a> <a class="header-anchor" href="#インストールソース詳解" aria-label="Permalink to &quot;[インストールソース詳解](./install-sources/)&quot;">​</a></h3><p>3つのインストールソースを詳しく説明：GitHubリポジトリ、ローカルパス、プライベートGitリポジトリ。それぞれの用途、コマンドフォーマット、注意事項を解説します。</p><h3 id="グローバルインストール-vs-プロジェクトローカルインストール" tabindex="-1"><a href="./global-vs-project/">グローバルインストール vs プロジェクトローカルインストール</a> <a class="header-anchor" href="#グローバルインストール-vs-プロジェクトローカルインストール" aria-label="Permalink to &quot;[グローバルインストール vs プロジェクトローカルインストール](./global-vs-project/)&quot;">​</a></h3><p><code>--global</code>とデフォルト（プロジェクトローカル）インストールの違いを説明し、適切なインストール場所の選び方、スキル検索の優先順位ルールを理解するのに役立ちます。</p><h3 id="インストール済みスキルのリスト表示" tabindex="-1"><a href="./list-skills/">インストール済みスキルのリスト表示</a> <a class="header-anchor" href="#インストール済みスキルのリスト表示" aria-label="Permalink to &quot;[インストール済みスキルのリスト表示](./list-skills/)&quot;">​</a></h3><p><code>list</code>コマンドを使用してインストール済みスキルを表示する方法を学び、<code>(project)</code>と<code>(global)</code>位置タグの意味を理解しましょう。</p><h3 id="スキルの更新" tabindex="-1"><a href="./update-skills/">スキルの更新</a> <a class="header-anchor" href="#スキルの更新" aria-label="Permalink to &quot;[スキルの更新](./update-skills/)&quot;">​</a></h3><p><code>update</code>コマンドを使用してインストール済みスキルを更新する方法をガイドします。すべてを更新するか、特定のスキルを更新するかを選択でき、スキルとソースリポジトリを同期させます。</p><h3 id="スキルの削除" tabindex="-1"><a href="./remove-skills/">スキルの削除</a> <a class="header-anchor" href="#スキルの削除" aria-label="Permalink to &quot;[スキルの削除](./remove-skills/)&quot;">​</a></h3><p>2つの削除方法を紹介：インタラクティブな<code>manage</code>コマンドとスクリプト化された<code>remove</code>コマンド。スキルライブラリを効率的に管理するのに役立ちます。</p><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><p>ニーズに応じて、適切な学習パスを選択してください：</p><h3 id="パス-a-システマティックな学習-初心者におすすめ" tabindex="-1">パス A：システマティックな学習（初心者におすすめ） <a class="header-anchor" href="#パス-a-システマティックな学習-初心者におすすめ" aria-label="Permalink to &quot;パス A：システマティックな学習（初心者におすすめ）&quot;">​</a></h3><p>すべての内容を順序立てて学び、完全な知識体系を構築します：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>コマンド詳解 → インストールソース → グローバル vs プロジェクト → スキルのリスト表示 → スキルの更新 → スキルの削除</span></span></code></pre></div><h3 id="パス-b-ニーズに応じた参照" tabindex="-1">パス B：ニーズに応じた参照 <a class="header-anchor" href="#パス-b-ニーズに応じた参照" aria-label="Permalink to &quot;パス B：ニーズに応じた参照&quot;">​</a></h3><p>現在のタスクに応じて直接ジャンプします：</p><table tabindex="0"><thead><tr><th>やりたいこと</th><th>この記事を読む</th></tr></thead><tbody><tr><td>コマンドの使い方を確認する</td><td><a href="./cli-commands/">コマンド詳解</a></td></tr><tr><td>プライベートリポジトリからスキルをインストールする</td><td><a href="./install-sources/">インストールソース詳解</a></td></tr><tr><td>グローバルかプロジェクトかを決める</td><td><a href="./global-vs-project/">グローバル vs プロジェクト</a></td></tr><tr><td>インストール済みスキルを確認する</td><td><a href="./list-skills/">インストール済みスキルのリスト表示</a></td></tr><tr><td>スキルを最新バージョンに更新する</td><td><a href="./update-skills/">スキルの更新</a></td></tr><tr><td>使わないスキルを削除する</td><td><a href="./remove-skills/">スキルの削除</a></td></tr></tbody></table><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>このセクションを完了すると、OpenSkills の日常的な使用スキルを習得したことになります。次にできること：</p><ul><li><strong><a href="./../advanced/">高度な機能</a></strong>：Universal モード、カスタム出力パス、シンボリックリンク、カスタムスキルの作成などの高度な機能を学ぶ</li><li><strong><a href="./../faq/">よくある質問</a></strong>：問題に遭遇した場合、FAQ とトラブルシューティングガイドを参照する</li></ul>',29)])])}const b=e(s,[["render",i]]);export{u as __pageData,b as default};
